import React, { useState } from 'react';
import { motion } from 'framer-motion'; // Ensure 'npm install framer-motion' was run
import axios from 'axios';

<div style={{ position: 'relative', background: '#000', borderRadius: '15px', overflow: 'hidden' }}>
  <h4 style={{ color: '#1E88E5', textAlign: 'center', padding: '10px' }}>AI Boundary Marking</h4>
  
  {/* Layer 1: The Original MRI (Visible) */}
  {preview && (
    <img 
      src={preview} 
      style={{ width: '100%', display: 'block', borderRadius: '0 0 10px 10px' }} 
      alt="MRI" 
    />
  )}
  
  {/* Layer 2: The Green Mask (Stacked on Top) */}
  {data?.mask && (
    <img 
      src={data.mask} 
      style={{ 
        position: 'absolute', 
        top: '48px', // Adjust this to match the height of your <h4> header
        left: 0, 
        width: '100%', 
        height: 'calc(100% - 48px)',
        filter: 'hue-rotate(90deg) saturate(20) brightness(1.5)', // Turns white prediction to Green
        mixBlendMode: 'screen', // Makes the black background of the mask transparent
        pointerEvents: 'none' 
      }} 
      alt="Tumor Mask"
    />
  )}
</div>

const Dashboard = () => {
  const [preview, setPreview] = useState(null);
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setPreview(URL.createObjectURL(file));
    setLoading(true);

    const formData = new FormData();
    formData.append('file', file);

    try {
      const res = await axios.post('http://localhost:5000/analyze', formData);
      setData(res.data);
    } catch (err) {
      alert("Network Error: Ensure the Flask terminal is still running.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: '40px', background: '#F5F7FA', minHeight: '100vh' }}>
      <h1>AI Diagnostic Hub</h1>
      <input type="file" onChange={handleUpload} style={{ marginBottom: '20px' }} />

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
        <div style={{ background: '#000', padding: '10px', borderRadius: '15px' }}>
          <h4 style={{ color: '#fff', textAlign: 'center' }}>Original Scan</h4>
          {preview && <img src={preview} style={{ width: '100%', borderRadius: '10px' }} alt="MRI" />}
        </div>

        <div style={{ background: '#000', padding: '10px', borderRadius: '15px', position: 'relative' }}>
          <h4 style={{ color: '#1E88E5', textAlign: 'center' }}>AI Boundary Marking</h4>
          {preview && <img src={preview} style={{ width: '100%', borderRadius: '10px', opacity: 0.8 }} alt="Base" />}
          {data?.mask && (
            <motion.img 
              initial={{ opacity: 0 }} 
              animate={{ opacity: 0.7 }} 
              src={data.mask} 
              style={{ 
                position: 'absolute', top: '48px', left: '10px', width: 'calc(100% - 20px)',
                filter: 'hue-rotate(90deg) saturate(20) brightness(1.2)', // Turns mask green
                mixBlendMode: 'screen', pointerEvents: 'none'
              }} 
            />
          )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
